const body = $input.first().json.body;

// Extract call data from Vapi end-of-call-report
const call = body.message ? body.message.call : body.call;
const callObj = call || {};

const callId = callObj.id || body.call_id || 'unknown-' + Date.now();
const transcript = body.message ? (body.message.artifact && body.message.artifact.transcript) : body.transcript;
const transcriptText = transcript || '';

// Check if user actually spoke (not just AI greeting)
// Filter for User turns with meaningful content (> 5 chars after prefix)
const userTurns = transcriptText.split('\n')
  .filter(line => line.startsWith('User:'))
  .filter(line => line.replace('User:', '').trim().length > 5);
const hasTranscript = userTurns.length >= 1;

// Calculate duration
let callDurationSeconds = null;
let callStartedAt = null;
if (callObj.startedAt && callObj.endedAt) {
  const start = new Date(callObj.startedAt);
  const end = new Date(callObj.endedAt);
  callDurationSeconds = Math.round((end - start) / 1000);
  callStartedAt = callObj.startedAt;
} else if (callObj.startedAt) {
  callStartedAt = callObj.startedAt;
}

const endedReason = body.message ? body.message.endedReason : (body.endedReason || 'unknown');
const phone = callObj.customer ? callObj.customer.number : null;

return [{ json: {
  callId,
  transcript: transcriptText,
  hasTranscript,
  callDurationSeconds,
  callStartedAt,
  endedReason,
  phone
} }];

const llmResponse = $input.first().json;
const extractData = $('Extract Call Data').first().json;

function clamp(val, min, max) {
  const n = parseInt(val);
  if (isNaN(n)) return min;
  return Math.min(Math.max(n, min), max);
}

function sanitizeStr(val, maxLen) {
  if (val === null || val === undefined) return null;
  const s = String(val).trim();
  if (s.length === 0) return null;
  return s.substring(0, maxLen || 500);
}

let parsed = {};
try {
  const content = llmResponse.choices && llmResponse.choices[0] && llmResponse.choices[0].message
    ? llmResponse.choices[0].message.content
    : JSON.stringify(llmResponse);
  parsed = JSON.parse(content);
} catch(e) {
  parsed = {
    score_company_size: 1,
    score_tech_stack: 1,
    score_pain_point: 1,
    score_timeline: 1,
    conversation_summary: 'Analyse nicht verfuegbar.',
    sentiment: 'neutral',
    objections_raised: [],
    drop_off_point: null,
    is_decision_maker: false,
    status: 'contacted',
    next_steps: [],
    caller_name: null,
    company: null,
    company_size: null,
    current_stack: null,
    pain_point: null,
    timeline: null
  };
}

const result = {
  callId: extractData.callId,
  phone: extractData.phone,
  callDurationSeconds: extractData.callDurationSeconds,
  callStartedAt: extractData.callStartedAt,
  transcript: extractData.transcript,
  score_company_size: clamp(parsed.score_company_size, 1, 3),
  score_tech_stack: clamp(parsed.score_tech_stack, 1, 3),
  score_pain_point: clamp(parsed.score_pain_point, 1, 3),
  score_timeline: clamp(parsed.score_timeline, 1, 3),
  conversation_summary: String(parsed.conversation_summary || '').substring(0, 1000),
  sentiment: ['positiv', 'neutral', 'negativ'].includes(parsed.sentiment) ? parsed.sentiment : 'neutral',
  objections_raised: Array.isArray(parsed.objections_raised) ? parsed.objections_raised : [],
  drop_off_point: parsed.drop_off_point || null,
  is_decision_maker: Boolean(parsed.is_decision_maker),
  status: ['new','contacted','qualified','appointment_booked','converted','lost'].includes(parsed.status) ? parsed.status : 'contacted',
  next_steps: Array.isArray(parsed.next_steps) ? parsed.next_steps : [],
  caller_name: sanitizeStr(parsed.caller_name, 200),
  company: sanitizeStr(parsed.company, 200),
  company_size: sanitizeStr(parsed.company_size, 200),
  current_stack: sanitizeStr(parsed.current_stack, 500),
  pain_point: sanitizeStr(parsed.pain_point, 500),
  timeline: sanitizeStr(parsed.timeline, 200)
};

return [{ json: result }];

let d;
try {
  d = $('Detect New Categories').first().json;
} catch(e) {
  d = $input.first().json;
}

return [{ json: {
  callId: d.callId,
  score_company_size: d.score_company_size,
  score_tech_stack: d.score_tech_stack,
  score_pain_point: d.score_pain_point,
  score_timeline: d.score_timeline,
  conversation_summary: d.conversation_summary || '',
  sentiment: d.sentiment || 'neutral',
  objections_raised: Array.isArray(d.objections_raised) ? d.objections_raised : [],
  drop_off_point: d.drop_off_point || null,
  is_decision_maker: Boolean(d.is_decision_maker),
  status: d.status || 'contacted',
  next_steps: Array.isArray(d.next_steps) ? d.next_steps : [],
  transcript: d.transcript || '',
  callDurationSeconds: d.callDurationSeconds || null,
  callStartedAt: d.callStartedAt || null,
  phone: d.phone || null,
  caller_name: d.caller_name || null,
  company: d.company || null,
  company_size: d.company_size || null,
  current_stack: d.current_stack || null,
  pain_point: d.pain_point || null,
  timeline: d.timeline || null
} }];

const parsed = $input.first().json;
const extractData = $('Extract Call Data').first().json;
let existingNames = [];
try {
  existingNames = $('Build OpenRouter Request').first().json.existingCategoryNames || [];
} catch(e) {}
const normalize = (s) => s.trim().replace(/\s+/g, ' ');
const objections = Array.isArray(parsed.objections_raised) ? parsed.objections_raised : [];
const existingLower = existingNames.map(n => normalize(n).toLowerCase());
const newCats = objections.filter(obj => !existingLower.includes(normalize(obj).toLowerCase()));
const seen = new Set();
const uniqueNew = [];
for (const cat of newCats) {
  const key = normalize(cat).toLowerCase();
  if (!seen.has(key)) { seen.add(key); uniqueNew.push(normalize(cat)); }
}
const upsertBody = uniqueNew.map(name => ({ name, description: null, counter_argument: null, is_active: true, occurrence_count: 0 }));
return [{ json: { ...parsed, callId: parsed.callId || extractData.callId, phone: parsed.phone || extractData.phone, callDurationSeconds: parsed.callDurationSeconds || extractData.callDurationSeconds, callStartedAt: parsed.callStartedAt || extractData.callStartedAt, transcript: parsed.transcript || extractData.transcript, upsertBody: JSON.stringify(upsertBody), hasNewCategories: uniqueNew.length > 0 } }];
